import collections

class IntToChar(collections.Mapping):

    def __init__(self):
        self.store = {}

    def __getitem__(self, key):
        if isinstance(key, collections.Mapping):
            return ''.join(key.values())
        elif isinstance(key, list):
            return ''.join(key)
        elif isinstance(key, dict):
            return ''.join(key)
        elif isinstance(key, (str, int, tuple)):
            return key
        else:
            raise TypeError

    def __iter__(self):
        return iter(self.store)

    def __len__(self):
        return len(self.store)

    def __contains__(self, key):
        return key in self.store

    def keys(self):
        return self.store.keys()

    def values(self):
        return self.store.values()

    def items(self):
        return self.store.items()

    def __unicode__(self, default='?'):
        return unicode(''.join(self.values()), default)

    def __str__(self, default='?'):
        return str(''.join(self.values()), default)

