class DinnerParty(object):
    def __init__(self, host):
        self.host = host
        self.guests = []

    def invite(self, guest):
        if guest == self.host:
            raise ValueError("Host can't be a guest!")

        self.guests.append(guest)

    def describe(self):
        if len(self.guests) == 0:
            return "{} has no guests tonight.".format(self.host.name)

        guest_names = [x.name for x in self.guests]
        names = ', '.join(guest_names)
        return "{} invites {} to her dinner party.".format(self.host.name, names)

    def json(self):
        guests = [guest.to_json() for guest in self.guests]
        return json.dumps({"host": self.host.to_json(),
                           "guests": guests}, separators=(',', ':'))

