from flask import render_template_string

app = Flask(__name__)

@app.route("/")
def home():
    user = {'username': request.args.get('username')}
    template = '''
    <h1>Welcome to the dinner party, {{username}}!</h1>
    '''
    return render_template_string(template, **user)

if __name__ == "__main__":
    app.run()

