import os

def read_file(filename):
    path = os.path.join("/home/user/data", filename)
    with open(path) as f:
        return f.read()

def main():
    data_dir = "/home/user/data"
    files = os.listdir(data_dir)

    for f in files:
        data = read_file(f)
        print(data)

if __name__ == "__main__":
    main()
